  return arr.slice(____, ____);
}

solution:
function getFirstHalf(arr) {
  const mid = Math.ceil(arr.length / 2);
  return arr.slice(0, mid);
}

skeletonHint:
function removeEveryOther(arr) {
  for (let i = 1; i < arr.length; i += ____) {
    arr.splice(i, 1);
  }
  return arr;
}

solution:
function removeEveryOther(arr) {
  for (let i = 1; i < arr.length; i++) {
    arr.splice(i, 1);
    // No need to increment i by 2 because the next 'every other' element 
    // shifts into the current index position after splice.
  }
  return arr;
}

